import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {This algorithm utilizes a weighted score that combines inverse distance, predicted waiting time at the node, and a penalty factor based on the proximity to depot, incorporating randomness to encourage varied routing.}
    """
    # Step 1: Calculate baseline inverse distance scores for each unvisited node.
    inverse_distance_scores = {node: 1.0 / (distance_matrix[current_node, node] + 1.e-5) for node in unvisited_nodes}

    # Step 2: Estimate waiting time at each node as an inverse function of the node's connectivity or traffic index.
    waiting_time_factors = {node: 1.0 / (np.random.uniform(1, 10)) for node in unvisited_nodes}

    # Step 3: Introduce a penalty factor based on the distance to the depot, to favor nodes closer to the depot as the route progresses.
    depot_proximity_penalty = {node: 1.0 / (distance_matrix[node, depot_node] + 1.e-5) for node in unvisited_nodes}

    # Step 4: Combine these scores, factoring in a stochastic component for diversity.
    weighted_priority_scores = {
        node: (0.5 * inverse_distance_scores[node]) + 
              (0.3 * waiting_time_factors[node]) - 
              (0.2 * depot_proximity_penalty[node]) + 
              np.random.uniform(0, 0.1)
        for node in unvisited_nodes
    }

    # Step 5: Select the node with the highest weighted priority score.
    next_node = max(weighted_priority_scores, key=weighted_priority_scores.get)

    # Step 6: Adjust for diversity if another truck is also heading towards this next_node.
    if next_node in truck_nodes:
        unvisited_reduced = [node for node in unvisited_nodes if node != next_node]
        next_node = max(unvisited_reduced, key=lambda node: weighted_priority_scores[node])

    return next_node
